/**
 * Get pre-computed verdict for a topic.
 */
export function getMockVerdict(topicId: string): JudgingResult | undefined {
  return MOCK_VERDICTS[topicId];
}

/**
 * Check if a pre-computed verdict exists for a topic.
 */
export function hasMockVerdict(topicId: string): boolean {
  return topicId in MOCK_VERDICTS;
}
